"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[369],{9825:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new SoundBuffer and starts its background prune task.\\n\\nThe prune task runs every 0.5 seconds and removes expired emissions from\\nthe buffer and expiry queue. It is cancelled on `:Destroy()`.","params":[],"returns":[{"desc":"","lua_type":"SoundBuffer"}],"function_type":"static","source":{"line":37,"path":"docs/SoundBuffer.lua"}},{"name":"Store","desc":"Stores an emission in the buffer.\\n\\nThe emission must already have `EmittedAt` and `ExpiresAt` set. If the\\nbuffer is at its 128-emission capacity, the oldest emission (earliest\\n`ExpiresAt`) is evicted to make room.","params":[{"name":"emission","desc":"A fully constructed emission.","lua_type":"SoundEmission"}],"returns":[],"function_type":"method","source":{"line":50,"path":"docs/SoundBuffer.lua"}},{"name":"Cancel","desc":"Immediately removes an emission from the active set.\\n\\nThe emission disappears from all subsequent `:IterateNear()` results.\\nThe expiry queue entry is left in place for performance \u2014 it will be\\nskipped silently during the next prune pass.\\n\\nReturns `true` if the emission was found and removed, `false` if it was\\nnot in the active set (already expired or never stored).","params":[{"name":"emissionId","desc":"The `Id` of the emission to cancel.","lua_type":"string"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":67,"path":"docs/SoundBuffer.lua"}},{"name":"IterateNear","desc":"Returns a stateful iterator over all active emissions within `maxRadius`\\nstuds of `position`.\\n\\nThe iteration is over a snapshot taken at call time \u2014 the active table\\ncan change safely during iteration.\\n\\n```lua\\nfor emission in buffer:IterateNear(listenerPos, 500) do\\n    -- process emission\\nend\\n```","params":[{"name":"position","desc":"The listener\'s world position.","lua_type":"Vector3"},{"name":"maxRadius","desc":"Maximum distance to consider, in studs.","lua_type":"number"}],"returns":[{"desc":"Iterator that yields SoundEmission objects within range.","lua_type":"() -> SoundEmission?"}],"function_type":"method","source":{"line":88,"path":"docs/SoundBuffer.lua"}},{"name":"GetCount","desc":"Returns the total number of active emissions currently in the buffer.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":95,"path":"docs/SoundBuffer.lua"}},{"name":"IsActive","desc":"Returns `true` if an emission with the given ID is currently active.","params":[{"name":"emissionId","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":103,"path":"docs/SoundBuffer.lua"}},{"name":"Destroy","desc":"Destroys the buffer, cancels the prune task, and clears all emissions.\\n\\nIdempotent \u2014 safe to call twice.","params":[],"returns":[],"function_type":"method","source":{"line":112,"path":"docs/SoundBuffer.lua"}}],"properties":[],"types":[],"name":"SoundBuffer","desc":"Persistence and lifecycle layer for active sound emissions.\\n\\nThe buffer solves a fundamental problem: any polling consumer calls\\n`:QueryPosition()` at discrete intervals, but sound events happen at\\narbitrary moments in continuous time. An instantaneous event like a\\ngunshot that fires at `t = 0.05` must still be detectable when a query\\nruns at `t = 0.1`, `t = 0.2`, and potentially `t = 0.3`.\\n\\nThe solution is a relevance window \u2014 each emission persists in the buffer\\nfor longer than its physical duration:\\n\\n```\\nExpiresAt = EmittedAt + Duration + DECAY_WINDOW (0.6s)\\n```\\n\\nA gunshot with a 0.05s physical duration stays in the buffer for 0.65s\\ntotal, ensuring it is visible to at least six consecutive 0.1s query ticks.\\n\\nSoundBuffer is managed internally by [Resonix] and does not need to be\\nconstructed directly.","source":{"line":25,"path":"docs/SoundBuffer.lua"}}')}}]);